local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LTimeBubble:LxNodeBase
local LTimeBubble = LxClass("LTimeBubble", LxNodeBase)

LTimeBubble.ROOT = "UIBubbleStick"

function LTimeBubble:LTimeBubble()
    self._bubbleTran = nil                -- 气泡预制体
    self._heroTrans = nil                 -- 英雄的位置
    self._uiCamera = nil                  -- UI摄像机
    self._sceneCamera = nil               -- 场景摄像机
    self._textBgTrans = nil               -- 时间背景图预制体
    self._offset = Vector3.New(0, 0, 0)   -- 偏移量
    self._path = "UI/Prefabs/Com"
    self._name = "TimeBubble"

    self._isDetroyed = false
    self._isVisible = true
    self._isTextBgVisible = true
    self._timer = nil
	self._clickFunc = nil

    ---@type LDisplayPrefab
    self._dpPrefab = nil
end

------------------------------------------------------------------
function LTimeBubble:IsBubbleTranValid()
    return self._bubbleTran and CS.IsValidObject(self._bubbleTran)
end

function LTimeBubble:InitBubbleRoot()
    local rootCanvas = LGameUI.GetUIFight()
    self._uiCamera = LGameUI.GetUICamera()
    self._sceneCamera = gLGameScene:GetCurrentSceneCamera()

    local parentTrans = CS.FindTrans(rootCanvas,LTimeBubble.ROOT)
    if parentTrans then
        parentTrans = CS.NewObject(LTimeBubble.ROOT, rootCanvas)
    end
    self._parentTrans = parentTrans
end

function LTimeBubble:OnLoaded(dp)
    local instanceTrans = dp:GetDisplayTrans()
    local parentTrans = self._parentTrans
    if instanceTrans then
        local instanceGo = instanceTrans.gameObject
        self._bubbleTran = instanceTrans
		
		local follow = instanceTrans:GetComponent(typeofBtHudFollow)
		if not follow then
			follow = instanceTrans.gameObject:AddComponent(typeofBtHudFollow)
		end
        self._bubbleFollow = follow
        local textBgTrans = CS.FindTrans(instanceTrans, "timeBg")
        self._text = CS.FindTrans(textBgTrans, "text")
        self._textBgTrans = textBgTrans
        self:OnUpdateHeroTrans()
    end
end

function LTimeBubble:OnUpdateHeroTrans()
    if not self:IsBubbleTranValid() then return end

	self._bubbleFollow:Init(self._uiCamera, self._sceneCamera)
	self._bubbleFollow:DoFollowTrans(self._heroTrans, self._offset)

    self:SetXTextContent(self._text, self._timeStr)
    CS.ShowObject(self._bubbleTran,self._isVisible)
    CS.ShowObject(self._textBgTrans, self._isTextBgVisible)
	if self._clickFunc then
		LxUiHelper.SetTransClick(self._bubbleTran, self._clickFunc)
	end
    
    if self._clickScale then
    	local clickScale = self._bubbleTran:GetComponent(typeClickScale)
    	if not clickScale then
    		clickScale = self._bubbleTran.gameObject:AddComponent(typeClickScale)
    	else
    		clickScale.enabled = true
    	end
    end

end


-----------------------------------------
function LTimeBubble:ClearDpPrefab()
    if self._dpPrefab then
        self._dpPrefab:Destroy()
        self._dpPrefab = nil
    end
end

function LTimeBubble:CreateBubble(prefabName)
    self:InitBubbleRoot()
    if self:IsBubbleTranValid() then
        if not string.isempty(prefabName) and prefabName~= self._name then
            self:ClearDpPrefab()
            self._bubbleTran = nil 
        else
            return
        end
    end

    if not string.isempty(prefabName) then
        self._name = prefabName
    end

    self:ClearDpPrefab()
	
    local dpPrefab = LDisplayPrefab:New()
    self._dpPrefab = dpPrefab
    dpPrefab:CreatePrefab(self._parentTrans, self._path, self._name)
    dpPrefab:SetLoadedFunction(function (dp)
        self:OnLoaded(dp)
    end)
    dpPrefab:StartLoad()
end

function LTimeBubble:DestroyBubble()
    if self._isDetroyed then return end

	if self._timer then
		LxTimer.LoopTimeStop(self._timer)
		self._timer = nil
	end
    
    self:ClearDpPrefab()
    LxNodeBase.Dispose(self)
    self._isDetroyed = true
end

function LTimeBubble:SetVisible(isVisible)
    if self._isVisible == isVisible then return end

    self._isVisible = isVisible
    if not self:IsBubbleTranValid() then return end

    CS.ShowObject(self._bubbleTran,isVisible)
end

function LTimeBubble:SetTextBgVisible(isVisible)
    if self._isTextBgVisible == isVisible then return end

    self._isTextBgVisible = isVisible
    if not (self._textBgTrans and CS.IsValidObject(self._textBgTrans)) then return end

    CS.ShowObject(self._textBgTrans,isVisible)
end

function LTimeBubble:SetHeroTrans(heroTrans,offset)
    self._heroTrans = heroTrans
    self._offset = offset
    self:OnUpdateHeroTrans()
end

function LTimeBubble:SetTimeStr(timeStr)
    self._timeStr = timeStr
	if not self:IsBubbleTranValid() then return end
    
	self:SetXTextContent(self._text, self._timeStr)
end

function LTimeBubble:SetTime(time)
    self._time = time
	local timeStr = LUtil.FormatTimespanNumber(time)
	self:SetTimeStr(timeStr)
	
	if self._timer then
		LxTimer.LoopTimeStop(self._timer)
		self._timer = nil
	end
	
	if time > 0 then
		self._timer = LxTimer.LoopTimeCall(function()
			self._time = self._time - 1
			local timeStr = LUtil.FormatTimespanNumber(self._time)
			self:SetTimeStr(timeStr)
			if self._time <= 0 then
				LxTimer.LoopTimeStop(self._timer)
				self._timer = nil
			end
		end, 1, false, -1)
	end
end

--显示 天：时 格式
function LTimeBubble:SetTimeCn(time)
    self._time = time
    local timeStr = LUtil.FormatTimespanCn(time, {hTextId = 10371})
    self:SetTimeStr(timeStr)

    if self._timer then
        LxTimer.LoopTimeStop(self._timer)
        self._timer = nil
    end

    if time > 0 then
        self._timer = LxTimer.LoopTimeCall(function()
            self._time = self._time - 1
            local timeStr = LUtil.FormatTimespanCn(self._time, {hTextId = 10371})
            self:SetTimeStr(timeStr)
            if self._time <= 0 then
                LxTimer.LoopTimeStop(self._timer)
                self._timer = nil
            end
        end, 1, false, -1)
    end
end

function LTimeBubble:AddClickFunc(clickFun, bClickScale)
	self._clickFunc = clickFun
    self._clickScale = bClickScale
	self:OnUpdateHeroTrans()
end

return LTimeBubble